 - entity_name: "content"
   business_concept: "Media Title"
   description: "Dimension table for the video content catalog."
   aliases: ["titles", "media"]
   base_table: { database: "Netflix", schema: "Consum", table: "content" }
   columns:
     - { name: "content_id", description: "Unique identifier for each content item.", data_type: "INT", is_primary_key: true, sample_values: [7, 8] }
     - { name: "title", description: "The official display name of the content item.", data_type: "VARCHAR(90)", sample_values: ["Going Clear: Scientology and the Prison of Belief", "The Blood of Fu Manchu"] }
     - { name: "episode", description: "The episode number (0 for movies).", data_type: "INT", sample_values: [2, 19] }
     - { name: "genre", description: "Primary classification of the content. Can be a pipe-separated list.", data_type: "VARCHAR(29)", sample_values: ["Documentary", "Adventure|Crime|Horror"] }
     - { name: "duration", description: "The total runtime in minutes.", data_type: "INT", sample_values: [73, 47] }
     - name: "cost_per_stream"
       description: "Raw licensing cost per view as text, including currency. WARNING: Do NOT use this column directly. You MUST use the 'Cost Per Stream (USD)' or 'Cost Per Stream (EUR)' for calculations, and 'Cost Currency' for identification."
       data_type: "VARCHAR(6)"
       derived_metric_name: ["Cost Per Stream (USD)", "Cost Per Stream (EUR)", "Cost Currency"]
       sample_values: ["$20.73", "$5.05"]
     - name: "release_date"
       description: "Original release date. WARNING: Stored as text. For date operations, use the 'Typed Release Date' metric."
       data_type: "VARCHAR(11)"
       derived_metric_name: "Typed Release Date"
       sample_values: ["29-Oct-2005", "07-Jan-2006"]
     - { name: "distributor", description: "The rights holder or distributor.", data_type: "VARCHAR(36)", sample_values: ["Kuphal, Sipes and Collier", "Von LLC"] }
